diff --git a/completions.go b/completions.go
index d3607c2..8eba379 100644
--- a/completions.go
+++ b/completions.go
@@ -682,6 +682,29 @@ func checkIfFlagCompletion(finalCmd *Command, args []string, lastArg string) (*p
                        lastArg = lastArg[index+1:]
                        flagWithEqual = true
                } else {
+                       // When lastArg starts with '-', it could either be a new flag name or a flag
+                       // value that legitimately starts with a dash (e.g., --offset -10).
+                       // Check if the previous argument is a flag expecting a value; if so, treat
+                       // lastArg as that flag's value rather than as a new flag name.
+                       if len(args) > 0 {
+                               prevArg := args[len(args)-1]
+                               if isFlagArg(prevArg) {
+                                       if index := strings.Index(prevArg, "="); index < 0 {
+                                               var prevFlagName string
+                                               if strings.HasPrefix(prevArg, "--") {
+                                                       prevFlagName = prevArg[2:]
+                                               } else {
+                                                       prevFlagName = prevArg[len(prevArg)-1:]
+                                               }
+                                               prevFlag := findFlag(finalCmd, prevFlagName)
+                                               if prevFlag != nil && len(prevFlag.NoOptDefVal) == 0 {
+                                                       // Previous flag expects a value; suppress flag-name completion.
+                                                       trimmedArgs = args[:len(args)-1]
+                                                       return prevFlag, trimmedArgs, lastArg, nil
+                                               }
+                                       }
+                               }
+                       }
                        // Normal flag completion
                        return nil, args, lastArg, nil
                }
